// Validate secret, extract content_id, read full content state
const data = $input.first().json;
const body = data.body || data;

const expectedSecret = $env.N8N_WEBHOOK_HMAC_SECRET;
if (!expectedSecret) throw new Error('N8N_WEBHOOK_HMAC_SECRET not configured');

const receivedSecret = (data.headers || {})['x-webhook-secret'] || body.secret || '';
if (receivedSecret !== expectedSecret) throw new Error('Unauthorized: invalid webhook secret');

const content_id = body.content_id;
if (!content_id) throw new Error('Missing required field: content_id');

// Read full content state from NocoDB
let content_state;
try {
  content_state = await $http.request({
    method: 'POST',
    url: 'http://localhost:5678/webhook/cf-read-content',
    headers: { 'Content-Type': 'application/json' },
    body: {
      secret: $env.N8N_WEBHOOK_HMAC_SECRET,
      action: 'read_content',
      content_id
    }
  });
} catch (e) {
  content_state = {};
}

// Parse stored step data
const cs = content_state.body || content_state;
let concept = {};
let casting = {};
let brief = {};
try { concept = JSON.parse(cs.step4_concept || '{}'); } catch {}
try { casting = JSON.parse(cs.step5_casting || '{}'); } catch {}
try { brief   = JSON.parse(cs.brief || '{}'); } catch { brief = cs.brief || {}; }

const title      = cs.title || '';
const format     = cs.format || 'reel';
const brand_tone = cs.brand_tone || cs.tone || 'professionnel et direct';

return [{ json: { content_id, title, format, brand_tone, brief, concept, casting } }];

// Step 6: Write Script — main creative writing step (premium model)
const data = $input.first().json;

let script_scenes;
try {
  const response = await $http.request({
    method: 'POST',
    url: 'http://litellm:4000/v1/chat/completions',
    headers: {
      'Authorization': `Bearer ${$env.LITELLM_API_KEY}`,
      'Content-Type': 'application/json'
    },
    body: {
      model: 'gpt-4o-mini',
      messages: [
        {
          role: 'system',
          content: `You are a professional scriptwriter for short-form Instagram video content (${data.format}). Brand tone: ${data.brand_tone}. Write a scene-by-scene script based on the concept document. Output ONLY a valid JSON array of scene objects. Each scene must have: scene_number (integer starting at 1), duration_seconds (integer, 2-8), action (string describing visual action), dialogue (string or null), visual_description (string, detailed, suitable for image prompt), transition (string: cut|fade|slide|none).`
        },
        {
          role: 'user',
          content: `Title: ${data.title}\nConcept hook: ${JSON.stringify(data.concept?.hook || '')}\nNarrative arc: ${JSON.stringify(data.concept?.narrative_arc || '')}\nVisual style: ${JSON.stringify(data.concept?.visual_style || '')}\nCTA: ${JSON.stringify(data.concept?.cta || '')}\nCasting: ${JSON.stringify(data.casting)}`
        }
      ],
      max_tokens: 4000,
      temperature: 0.8
    }
  });
  const text = response.choices?.[0]?.message?.content || '[]';
  // Strip markdown code fences if present
  const cleaned = text.replace(/^```(?:json)?\n?/m, '').replace(/\n?```$/m, '').trim();
  try { script_scenes = JSON.parse(cleaned); } catch { script_scenes = [{ raw: cleaned }]; }
  if (!Array.isArray(script_scenes)) script_scenes = [script_scenes];
} catch (e) {
  script_scenes = [{ error: e.message }];
}

return [{ json: { ...data, step6_script_scenes: script_scenes } }];

// Step 7: Storyboard Decomposition — create NocoDB scene rows via cf-scene
const data = $input.first().json;
const scenes = data.step6_script_scenes || [];

let scenes_created = 0;
const errors = [];

for (const scene of scenes) {
  if (!scene.scene_number) continue;
  try {
    await $http.request({
      method: 'POST',
      url: 'http://localhost:5678/webhook/cf-scene',
      headers: { 'Content-Type': 'application/json' },
      body: {
        secret: $env.N8N_WEBHOOK_HMAC_SECRET,
        action: 'create_scene',
        content_id: data.content_id,
        scene_number: scene.scene_number,
        description: scene.visual_description || scene.action || '',
        duration: scene.duration_seconds || 5,
        dialogue: scene.dialogue || '',
        action: scene.action || '',
        transition: scene.transition || 'cut',
        status: 'pending',
        provider: ''
      }
    });
    scenes_created++;
  } catch (e) {
    errors.push(`Scene ${scene.scene_number}: ${e.message}`);
  }
}

return [{ json: { ...data, scenes_created, storyboard_errors: errors } }];

// Step 8: Sound Design Brief (eco model)
const data = $input.first().json;

let result;
try {
  const response = await $http.request({
    method: 'POST',
    url: 'http://litellm:4000/v1/chat/completions',
    headers: {
      'Authorization': `Bearer ${$env.LITELLM_API_KEY}`,
      'Content-Type': 'application/json'
    },
    body: {
      model: 'deepseek-v3',
      messages: [
        {
          role: 'system',
          content: 'Generate a sound design brief for this video content. Output as JSON with fields: music_style (string), music_mood (string), tempo_bpm (integer or null), sfx_list (array of objects with scene_number and sfx_description), voiceover_cues (array of objects with scene_number and cue_text), overall_audio_notes (string).'
        },
        {
          role: 'user',
          content: `Script scenes: ${JSON.stringify(data.step6_script_scenes)}\nVisual style: ${JSON.stringify(data.concept?.visual_style || '')}\nBrand tone: ${data.brand_tone}`
        }
      ],
      max_tokens: 1500,
      temperature: 0.5
    }
  });
  const text = response.choices?.[0]?.message?.content || '{}';
  try { result = JSON.parse(text); } catch { result = { raw: text }; }
} catch (e) {
  result = { error: e.message };
}

return [{ json: { ...data, step8_sound_design: result } }];

// Store all results in NocoDB via cf-update-content
const data = $input.first().json;

try {
  await $http.request({
    method: 'POST',
    url: 'http://localhost:5678/webhook/cf-update-content',
    headers: { 'Content-Type': 'application/json' },
    body: {
      secret: $env.N8N_WEBHOOK_HMAC_SECRET,
      action: 'update_content',
      content_id: data.content_id,
      fields: {
        current_step: 8,
        status: 'awaiting_validation',
        step6_script: JSON.stringify(data.step6_script_scenes),
        step7_scenes_count: data.scenes_created,
        step8_sound_design: JSON.stringify(data.step8_sound_design)
      }
    }
  });
} catch (e) {
  console.error('cf-update-content failed:', e.message);
}

return [{ json: data }];
